using MediatR; using Constriva.Application.Common.Behaviors; using Constriva.Domain.Entities.Contratos; using Constriva.Domain.Enums; using Constriva.Domain.Interfaces.Repositories; using Constriva.Application.Features.Contratos.DTOs; using Constriva.Application.Common.Interfaces;  namespace Constriva.Application.Features.Contratos;  public record GetContratosQuery(     Guid EmpresaId, Guid? ObraId = null, StatusContratoEnum? Status = null,     int Page = 1, int PageSize = 20)     : IRequest<PaginatedResult<ContratoDto>>, ITenantRequest;  public class GetContratosHandler : IRequestHandler<GetContratosQuery, PaginatedResult<ContratoDto>> {     private readonly IContratoRepository _repo;     public GetContratosHandler(IContratoRepository repo) => _repo = repo;      public async Task<PaginatedResult<ContratoDto>> Handle(GetContratosQuery r, CancellationToken ct)     {         var (items, total) = await _repo.GetPagedAsync(r.EmpresaId, r.ObraId, r.Status, r.Page, r.PageSize, ct);         return new PaginatedResult<ContratoDto>         {             Items = items.Select(ToDto), TotalCount = total, Page = r.Page, PageSize = r.PageSize         };     }      private static ContratoDto ToDto(Contrato c) => new(         c.Id, c.Numero, c.Objeto, c.Tipo, c.Status,         c.ObraId, c.FornecedorId,         c.Fornecedor != null ? (c.Fornecedor.NomeFantasia ?? c.Fornecedor.RazaoSocial) : null,         c.ValorGlobal, c.ValorMedidoAcumulado,         c.ValorGlobal > 0 ? Math.Round(c.ValorMedidoAcumulado / c.ValorGlobal * 100, 2) : 0,         c.DataAssinatura, c.DataVigenciaInicio, c.DataVigenciaFim,         c.Observacoes, c.CreatedAt); } 